import{_ as a,c as e,o as i,a as r}from"./app.84857f77.js";const _=JSON.parse('{"title":"第 1 章：概論","description":"","frontmatter":{"title":"第 1 章：概論"},"headers":[{"level":2,"title":"1-1 Java 是當前最紅程式語言","slug":"_1-1-java-是當前最紅程式語言","link":"#_1-1-java-是當前最紅程式語言","children":[]},{"level":2,"title":"1-2 Java 的歷史","slug":"_1-2-java-的歷史","link":"#_1-2-java-的歷史","children":[]},{"level":2,"title":"1-3 Java 的特色","slug":"_1-3-java-的特色","link":"#_1-3-java-的特色","children":[]}],"relativePath":"guide/zero/chapter_1.md"}'),l={name:"guide/zero/chapter_1.md"},d=r('<h1 id="第-1-章-概論" tabindex="-1">第 1 章：概論 <a class="header-anchor" href="#第-1-章-概論" aria-hidden="true">#</a></h1><h2 id="_1-1-java-是當前最紅程式語言" tabindex="-1">1-1 Java 是當前最紅程式語言 <a class="header-anchor" href="#_1-1-java-是當前最紅程式語言" aria-hidden="true">#</a></h2><p><a href="https://www.tiobe.com/tiobe-index" target="_blank" rel="noreferrer">TIOBE</a>，調查美國大企業使用程式語言的種類，2018年Java是排行第一名。</p><h2 id="_1-2-java-的歷史" tabindex="-1">1-2 Java 的歷史 <a class="header-anchor" href="#_1-2-java-的歷史" aria-hidden="true">#</a></h2><ul><li>1995 年 5 月，Java 語言誕生。</li><li>1996 年 1 月，第一個 JDK-JDK1.0 誕生。</li><li>1996 年 4 月，10 個最主要的作業系統供應商，申明將在其產品中嵌入 Java 技術。</li><li>1997 年 2 月，JDK1.1 釋出。</li><li>1998 年 12 月，Java2 企業平台 J2EE 釋出。</li><li>1999 年 6 月，SUN 公司釋出 Java 的三個版本：標準版(J2SE)、企業版(J2EE)和微型版(J2ME)。</li><li>2000 年 5 月，JDK1.3 釋出。</li><li>2000 年 5 月，JDK1.4 釋出。</li><li>2001 年 9 月，J2EE1.3 釋出。</li><li>2002 年 2 月，J2SE1.4 釋出，自此 Java 的計算能力有了大幅提升。</li><li>2004 年 9 月，J2SE1.5 釋出，成為 Java 語言發展史上的又一里程碑，為了表示該版本的重要性，J2SE1.5 更名為 Java SE 5.0。</li><li>2005 年 6 月，SUN 公司公開 Java SE 6。此時，Java 的各種版本已經更名，已取消其中的數字「 2 」：J2EE 更名為 Java EE (企業版)，J2SE 更名為 Java SE (標準版)，J2ME 更名為 Java ME (精簡版)。</li><li>2006 年 12 月，SUN 公司釋出 JRE6.0。</li><li>2009 年 12 月，SUN 公司釋出 Java EE 6。</li><li>2010 年 11 月，由於 Oracle 公司併購 Sun，所以 Java 技術的開發與推廣改由 Oracle (甲骨文) 公司接手。</li><li>2011 年 7 月，Oracle 公司發布 Java SE 7。</li><li>2014 年 3 月，Oracle 公司發布 Java SE 8。</li><li>2017 年 9 月，Oracle 公司發布 Java SE 9。</li><li>2018 年 3 月，Oracle 公司發布 Java SE 10。</li></ul><h2 id="_1-3-java-的特色" tabindex="-1">1-3 Java 的特色 <a class="header-anchor" href="#_1-3-java-的特色" aria-hidden="true">#</a></h2><p>根據昇陽公司當時的廣告，Java 的特色有：</p><ul><li><h3 id="簡單的-simple" tabindex="-1">簡單的 (Simple) <a class="header-anchor" href="#簡單的-simple" aria-hidden="true">#</a></h3><ul><li><code>Java</code> 號稱比 <code>C++</code> 簡單。</li><li><code>Java</code> 移除 <code>指標</code> 並用 <code>介面 (Interface)</code> 取代 <code>多重繼承</code>。</li><li><code>C++</code> 必須由程式設計者動態的分配與收集記憶體，但 <code>Java</code> 卻將記憶體回收與管理改為自動化。</li></ul></li><li><h3 id="物件導向的-object-oriented" tabindex="-1">物件導向的 (Object-Oriented) <a class="header-anchor" href="#物件導向的-object-oriented" aria-hidden="true">#</a></h3><ul><li><code>Java</code> 是 第一個以物件導向為基礎所開發的程式語言。(備注 <code>C++</code> 是繼承 C，再加上物件導向)。</li><li>完整的物件包含 <code>方法</code> 與 <code>屬性</code>。</li><li>物件導向裡，要先將所有方法，依照其功能分類，此稱為「 <code>類別</code> 」，此類別不僅有方法也有屬性。</li><li>類別可以創造出許許多多的「 <code>物件</code> 」。</li><li>物件導向的特性：<code>封裝</code>、<code>繼承</code>、<code>多形</code>。</li></ul></li><li><h3 id="分散式的-distributed" tabindex="-1">分散式的 (Distributed) <a class="header-anchor" href="#分散式的-distributed" aria-hidden="true">#</a></h3><ul><li>所謂的 <code>分散式系統</code> 是指，數台電腦藉由網路連結，而一起工作，並彼此分享資料。</li></ul></li><li><h3 id="解譯式的-interpreted" tabindex="-1">解譯式的 (Interpreted) <a class="header-anchor" href="#解譯式的-interpreted" aria-hidden="true">#</a></h3></li><li><h3 id="穩健的-robust" tabindex="-1">穩健的 (Robust) <a class="header-anchor" href="#穩健的-robust" aria-hidden="true">#</a></h3></li><li><h3 id="安全的-secure" tabindex="-1">安全的 (Secure) <a class="header-anchor" href="#安全的-secure" aria-hidden="true">#</a></h3></li><li><h3 id="結構中立的-architecture-neutral" tabindex="-1">結構中立的 (Architecture-Neutral) <a class="header-anchor" href="#結構中立的-architecture-neutral" aria-hidden="true">#</a></h3></li><li><h3 id="可攜式的-portable" tabindex="-1">可攜式的 (Portable) <a class="header-anchor" href="#可攜式的-portable" aria-hidden="true">#</a></h3></li><li><h3 id="高效率的-performance" tabindex="-1">高效率的 (Performance) <a class="header-anchor" href="#高效率的-performance" aria-hidden="true">#</a></h3></li><li><h3 id="多執行緒的-multithreaded" tabindex="-1">多執行緒的 (Multithreaded) <a class="header-anchor" href="#多執行緒的-multithreaded" aria-hidden="true">#</a></h3></li><li><h3 id="動態的-dynamic" tabindex="-1">動態的 (Dynamic) <a class="header-anchor" href="#動態的-dynamic" aria-hidden="true">#</a></h3></li></ul>',8),t=[d];function c(h,o,n,s,u,J){return i(),e("div",null,t)}const E=a(l,[["render",c]]);export{_ as __pageData,E as default};
